import json

lines = open('ios_crash.ips').readlines()
crash = json.loads(''.join(lines[1:]))
images = crash.get('usedImages', [])

# Show SampleMAUI images info (both entries)
print("=== SampleMAUI Binary Images ===")
for i, img in enumerate(images):
    if 'SampleMAUI' in img.get('name',''):
        print(f"  [{i}] name={img['name']} base=0x{img['base']:x} uuid={img['uuid']} arch={img['arch']}")
        if 'path' in img:
            print(f"      path={img['path']}")
        if 'size' in img:
            print(f"      size={img['size']}")

# Check for more crash context
print("\n=== Additional Crash Fields ===")
for key in ['vmRegionInfo', 'vmregioninfo', 'processByPid', 'procName', 'procPath',
            'parentProc', 'coalitionName', 'captureTime', 'modelCode', 'isCorpse',
            'uptime', 'procLaunch', 'procRole', 'translated', 'extMods']:
    if key in crash:
        val = crash[key]
        if isinstance(val, str) and len(val) > 200:
            val = val[:200] + '...'
        print(f"  {key}: {val}")

# Check thread 0 name
threads = crash.get('threads', [])
if threads:
    t0 = threads[0]
    for k in ['name', 'id', 'threadState', 'triggered']:
        if k in t0:
            print(f"\n  Thread 0 {k}: {t0[k]}")

# Print any thread names
print("\n=== Thread Names ===")
for i, t in enumerate(threads):
    name = t.get('name', '')
    if name:
        print(f"  Thread #{i}: {name}")
